import {
  GET_NOTIFICATION_ASYNC,
  GET_NOTIFICATION_SUCCESS,
  GET_NOTIFICATION_FAILURE,
  GET_NOTIFICATION_PROCESSING,
  MARK_ALL_READ_ASYNC,
  MARK_ALL_READ_SUCCESS,
  MARK_ALL_READ_FAILURE,
  MARK_ALL_READ_PROCESSING,
  GET_NOTIFICATION_CLEAR,
  LOAD_MORE_NOTIFICATION_ASYNC,
  LOAD_MORE_NOTIFICATION_SUCCESS,
  LOAD_MORE_NOTIFICATION_LOADING,
  MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE,
  MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING,
  MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS,
  MARK_AS_READ_NOTIFICATION_BY_ID_ASYNC,
  GET_NOTIFICATIONS_UNREAD_ASYNC,
  GET_NOTIFICATIONS_UNREAD_SUCCESS,
  GET_NOTIFICATIONS_UNREAD_FAILURE,
  GET_NOTIFICATIONS_UNREAD_PROCESSING,
} from './contants';

export const getNotificationAsync = (payload: any) => ({
  type: GET_NOTIFICATION_ASYNC,
  payload,
});
export const getNotificationSuccess = (payload: any) =>
  ({ type: GET_NOTIFICATION_SUCCESS, payload } as const);
export const getNotificationFailure = (payload: any) =>
  ({ type: GET_NOTIFICATION_FAILURE, payload } as const);
export const getNotificationProcessing = (payload: boolean) =>
  ({ type: GET_NOTIFICATION_PROCESSING, payload } as const);
export const getNotificationClear = () =>
  ({ type: GET_NOTIFICATION_CLEAR } as const);

export const loadMoreNotificationAsync = (payload: any) => ({
  type: LOAD_MORE_NOTIFICATION_ASYNC,
  payload,
});
export const loadMoreNotificationSuccess = (payload: any) =>
  ({ type: LOAD_MORE_NOTIFICATION_SUCCESS, payload } as const);
export const loadMoreNotificationLoading = (payload: any) =>
  ({ type: LOAD_MORE_NOTIFICATION_LOADING, payload } as const);

export const markAllReadAsync = (payload: any) => ({
  type: MARK_ALL_READ_ASYNC,
  payload,
});
export const markAllReadSuccess = (payload: any) =>
  ({ type: MARK_ALL_READ_SUCCESS, payload } as const);
export const markAllReadFailure = (payload: any) =>
  ({ type: MARK_ALL_READ_FAILURE, payload } as const);
export const markAllReadProcessing = (payload: boolean) =>
  ({ type: MARK_ALL_READ_PROCESSING, payload } as const);

export const markAsReadAsync = (payload: any) => ({
  type: MARK_AS_READ_NOTIFICATION_BY_ID_ASYNC,
  payload,
});
export const markAsReadSuccess = (payload: any) =>
  ({ type: MARK_AS_READ_NOTIFICATION_BY_ID_SUCCESS, payload } as const);
export const markAsReadFailure = (payload: any) =>
  ({ type: MARK_AS_READ_NOTIFICATION_BY_ID_FAILURE, payload } as const);
export const markAsReadProcessing = (payload: boolean) =>
  ({ type: MARK_AS_READ_NOTIFICATION_BY_ID_PROCESSING, payload } as const);

export const getNotificationsUnreadAsync = () => ({
  type: GET_NOTIFICATIONS_UNREAD_ASYNC,
  payload: undefined,
});
export const getNotificationsUnreadSuccess = (payload: any) =>
  ({ type: GET_NOTIFICATIONS_UNREAD_SUCCESS, payload } as const);
export const getNotificationsUnreadFailure = (payload: any) =>
  ({ type: GET_NOTIFICATIONS_UNREAD_FAILURE, payload } as const);
export const getNotificationsUnreadProcessing = (payload: boolean) =>
  ({ type: GET_NOTIFICATIONS_UNREAD_PROCESSING, payload } as const);

export const actionNotification = {
  getNotificationAsync,
  getNotificationSuccess,
  getNotificationFailure,
  getNotificationProcessing,
  getNotificationClear,
  loadMoreNotificationAsync,
  loadMoreNotificationSuccess,
  loadMoreNotificationLoading,
  markAllReadAsync,
  markAllReadSuccess,
  markAllReadFailure,
  markAllReadProcessing,
  markAsReadAsync,
  markAsReadSuccess,
  markAsReadFailure,
  markAsReadProcessing,
  getNotificationsUnreadAsync,
  getNotificationsUnreadSuccess,
  getNotificationsUnreadFailure,
  getNotificationsUnreadProcessing,
};

export type NotificationAction = ReturnType<
  | typeof getNotificationAsync
  | typeof getNotificationSuccess
  | typeof getNotificationFailure
  | typeof getNotificationProcessing
  | typeof getNotificationClear
  | typeof loadMoreNotificationAsync
  | typeof loadMoreNotificationSuccess
  | typeof loadMoreNotificationLoading
  | typeof markAllReadAsync
  | typeof markAllReadSuccess
  | typeof markAllReadFailure
  | typeof markAllReadProcessing
  | typeof markAsReadAsync
  | typeof markAsReadSuccess
  | typeof markAsReadFailure
  | typeof markAsReadProcessing
  | typeof getNotificationsUnreadAsync
  | typeof getNotificationsUnreadSuccess
  | typeof getNotificationsUnreadFailure
  | typeof getNotificationsUnreadProcessing
>;
