import {
  GET_WORK_ORDER_DETAIL_SUCCESS,
  GET_WORK_ORDER_DETAIL_FAILED,
  GET_WORK_ORDER_DETAIL_PROGRESS,
  CLEAR_WORK_ORDER_DETAIL,
  GET_MATERIAL_LIST_SUCCESS,
  GET_MATERIAL_LIST_FAILED,
  GET_CHAT_GROUP_SUCCESS,
  GET_CHAT_GROUP_PROGRESS,
  GET_CHAT_GROUP_FAILED,
  CLEAR_CHECKLIST,
  GET_CHECKLIST_PROGRESS,
  GET_CHECKLIST_FAILED,
  GET_CHECKLIST_SUCCESS,
  GET_COMMENT_CHECKLIST_SUCCESS,
  GET_COMMENT_CHECKLIST_FAILED,
  SAVE_WORK_ORDER_CHECKLIST_SUCCESS,
  SAVE_WORK_ORDER_CHECKLIST_FAILED,
  SAVE_WORK_ORDER_CHECKLIST_PROGRESS,
  GET_JOB_READY_DATA_SUCCESS,
  GET_JOB_READY_DATA_FAILED,
  GET_JOB_READY_DATA_PROGRESS,
  SUBMIT_JOB_READY_FORM_SUCCESS,
  SUBMIT_JOB_READY_FORM_FAILED,
  SUBMIT_JOB_READY_FORM_PROGRESS,
  SAVE_JOB_READY_ITEM_SUCCESS,
  SAVE_JOB_READY_ITEM_FAILED,
  SAVE_JOB_READY_ITEM_PROGRESS,
  UPDATE_JOB_READY_ITEM_OPTION,
  CLEAR_JOB_READY_DATA,
  // Job Start Checklist
  GET_JOB_START_DATA_SUCCESS,
  GET_JOB_START_DATA_FAILED,
  GET_JOB_START_DATA_PROGRESS,
  UPDATE_MATERIAL_RECEIVED,
  UPDATE_JOB_START_CHECKLIST_TOGGLE,
  SUBMIT_JOB_START_SUCCESS,
  SUBMIT_JOB_START_FAILED,
  SUBMIT_JOB_START_PROGRESS,
  CLEAR_JOB_START_DATA,
  // Work Order Participants
  GET_WORK_ORDER_PARTICIPANTS_SUCCESS,
  GET_WORK_ORDER_PARTICIPANTS_FAILED,
  GET_WORK_ORDER_PARTICIPANTS_PROGRESS,
  CLEAR_WORK_ORDER_PARTICIPANTS,
  // Work Order Detail Participants
  GET_WORK_ORDER_DETAIL_PARTICIPANTS_SUCCESS,
  GET_WORK_ORDER_DETAIL_PARTICIPANTS_FAILED,
  GET_WORK_ORDER_DETAIL_PARTICIPANTS_PROGRESS,
  CLEAR_WORK_ORDER_DETAIL_PARTICIPANTS,
  // Material Delivered
  GET_MATERIAL_DELIVERED_SUCCESS,
  GET_MATERIAL_DELIVERED_FAILED,
  GET_MATERIAL_DELIVERED_PROGRESS,
  GET_MATERIAL_DELIVERED_CHAT_SUCCESS,
  GET_MATERIAL_DELIVERED_CHAT_FAILED,
  GET_MATERIAL_DELIVERED_CHAT_PROGRESS,
  CLEAR_MATERIAL_DELIVERED,
  // QI Inspection
  TOGGLE_QI_INSPECTION_CHECK,
  CLEAR_QI_INSPECTION,
  // Screen Key Constants
  SCREEN_KEY_JOB_START,
  SCREEN_KEY_MATERIAL,
  SCREEN_KEY_QI_INSPECTION,
} from './contants';
import { JobDetailAction } from './actions';
import { JobDetailState } from './types';

export const initialState: JobDetailState = {
  workOrder: {
    data: null,
    isLoading: false,
    error: null,
  },
  materialList: {
    data: null,
    isLoading: false,
    error: null,
  },
  chatGroup: {
    data: null,
    isLoading: false,
    error: null,
  },
  // Checklists keyed by screen - empty object initially
  checklists: {},
  saveWorkOrder: {
    data: null,
    isLoading: false,
    error: null,
  },
  // JobReady checklist state
  jobReadyData: {
    data: null,
    isLoading: false,
    error: null,
  },
  submitJobReady: {
    data: false,
    isLoading: false,
    error: null,
  },
  saveJobReadyItem: {
    data: false,
    isLoading: false,
    error: null,
  },
  // Job Start checklist state
  jobStartData: {
    data: null,
    isLoading: false,
    error: null,
  },
  submitJobStart: {
    data: false,
    isLoading: false,
    error: null,
  },
  // Work Order Participants
  participants: {
    data: [],
    isLoading: false,
    error: null,
  },
  // Work Order Detail for Participants (leader viewing member's job)
  participantWorkOrder: {
    data: null,
    isLoading: false,
    error: null,
  },
  // Material Delivered (read-only work order + delivery chat)
  materialDelivered: {
    data: null,
    isLoading: false,
    error: null,
  },
  materialDeliveredChat: {
    data: null,
    isLoading: false,
    error: null,
  },
};

export default function jobDetailReducer(
  state = initialState,
  action: JobDetailAction,
): JobDetailState {
  switch (action.type) {
    case GET_WORK_ORDER_DETAIL_SUCCESS:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_WORK_ORDER_DETAIL_FAILED:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };
    case GET_WORK_ORDER_DETAIL_PROGRESS:
      return {
        ...state,
        workOrder: {
          ...state.workOrder,
          isLoading: action.payload,
        },
      };
    case CLEAR_WORK_ORDER_DETAIL:
      // If participant flow is active, only clear owner-specific state
      // Preserve participants & participantWorkOrder data
      if (state.participantWorkOrder?.data) {
        return {
          ...state,
          workOrder: initialState.workOrder,
          materialList: initialState.materialList,
          chatGroup: initialState.chatGroup,
          saveWorkOrder: initialState.saveWorkOrder,
        };
      }
      // Full reset when completely exiting job detail feature
      return {
        ...initialState,
      };

    case GET_MATERIAL_LIST_SUCCESS:
      return {
        ...state,
        materialList: {
          ...state.materialList,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_MATERIAL_LIST_FAILED:
      return {
        ...state,
        materialList: {
          ...state.materialList,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_COMMENT_CHECKLIST_SUCCESS: {
      // screenKey comes from action (passed from Content)
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // No key = no update

      // For MaterialChecklistScreen, update jobStartData.materialChecklists
      if (screenKey === SCREEN_KEY_MATERIAL) {
        if (!state.jobStartData.data) return state;
        const updatedMaterials = state.jobStartData.data.materialChecklists.map(
          item => {
            if (item.id === action.payload.id) {
              return {
                ...item,
                ...action.payload,
              } as typeof item;
            }
            return item;
          },
        );
        return {
          ...state,
          jobStartData: {
            ...state.jobStartData,
            data: {
              ...state.jobStartData.data,
              materialChecklists: updatedMaterials,
            },
          },
        };
      }

      // For other screens, update checklists[screenKey]
      const currentChecklist = state.checklists[screenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            ...currentChecklist,
            data: Array.isArray(currentChecklist.data)
              ? currentChecklist.data.map(item =>
                  item.id === action.payload.id
                    ? {
                        ...item,
                        ...action.payload, // Merge all fields from response
                        // Preserve isChecked if response returns null or undefined (comment-only updates)
                        isChecked:
                          action.payload.isChecked != null
                            ? action.payload.isChecked
                            : item.isChecked,
                        // Preserve injected fields
                        canUpdate: item.canUpdate,
                        screenKey: item.screenKey,
                        userRole: item.userRole,
                        reason: item.reason,
                        // Preserve mode-detection fields (API response may not include these)
                        projectReadyChecklistId: item.projectReadyChecklistId,
                        jobStartChecklistId: item.jobStartChecklistId,
                      }
                    : item,
                )
              : [],
          },
        },
      };
    }
    case GET_COMMENT_CHECKLIST_FAILED: {
      // screenKey comes from action (passed from Content)
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // No key = no update
      const currentChecklist = state.checklists[screenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            ...currentChecklist,
            error: action.payload,
          },
        },
      };
    }

    case GET_CHAT_GROUP_SUCCESS:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };

    case GET_CHAT_GROUP_FAILED:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_CHAT_GROUP_PROGRESS:
      return {
        ...state,
        chatGroup: {
          ...state.chatGroup,
          isLoading: action.payload,
        },
      };

    case GET_CHECKLIST_SUCCESS: {
      // MODIFIED: Support keyed checklists - require screenKey
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // Safety: ignore if no screenKey
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            isLoading: false,
            error: null,
            data: action.payload,
          },
        },
      };
    }

    case GET_CHECKLIST_FAILED: {
      // MODIFIED: Support keyed checklists - require screenKey
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // Safety: ignore if no screenKey
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            isLoading: false,
            error: action.payload,
            data: [],
          },
        },
      };
    }

    case GET_CHECKLIST_PROGRESS: {
      // MODIFIED: Support keyed checklists - require screenKey
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // Safety: ignore if no screenKey
      const currentChecklist = state.checklists[screenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            ...currentChecklist,
            isLoading: action.payload,
          },
        },
      };
    }

    case CLEAR_CHECKLIST: {
      // MODIFIED: Support keyed checklists - clear specific key or all
      const screenKey = (action as any).screenKey;
      if (screenKey) {
        // Clear specific screen's checklist
        // eslint-disable-next-line @typescript-eslint/no-unused-vars
        const { [screenKey]: _removed, ...remainingChecklists } =
          state.checklists;
        return {
          ...state,
          checklists: remainingChecklists,
        };
      }
      // Clear all checklists if no screenKey provided
      return {
        ...state,
        checklists: {},
      };
    }

    case SAVE_WORK_ORDER_CHECKLIST_SUCCESS:
      // If participant flow is active, update participantWorkOrder instead of workOrder
      // This prevents corrupting owner's workOrder data with participant's save response
      if (state.participantWorkOrder?.data) {
        return {
          ...state,
          saveWorkOrder: {
            ...state.saveWorkOrder,
            isLoading: false,
            error: null,
            data: action.payload,
          },
          participantWorkOrder: {
            ...state.participantWorkOrder,
            data: action.payload,
          },
        };
      }
      // Default: update workOrder (owner mode)
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: false,
          error: null,
          data: action.payload,
        },
        workOrder: {
          ...state.workOrder,
          data: action.payload,
        },
      };
    case SAVE_WORK_ORDER_CHECKLIST_FAILED:
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: false,
          error: action.payload,
        },
      };
    case SAVE_WORK_ORDER_CHECKLIST_PROGRESS:
      return {
        ...state,
        saveWorkOrder: {
          ...state.saveWorkOrder,
          isLoading: action.payload,
        },
      };

    // JobReady Checklist Reducer Cases
    case GET_JOB_READY_DATA_SUCCESS: {
      // screenKey comes from action payload (passed from Content)
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state;
      // Get checklist items from API response
      const rawChecklistData = action.payload?.checklists || [];
      // Get isViewOnly from parent - if true, canUpdate should be false
      const isViewOnly = action.payload?.isViewOnly ?? false;
      // Inject canUpdate and screenKey into each checklist item
      const checklistDataWithCanUpdate = Array.isArray(rawChecklistData)
        ? rawChecklistData.map((item: any) => ({
            ...item,
            canUpdate: !isViewOnly, // If isViewOnly=true, canUpdate=false
            screenKey: screenKey, // Inject screenKey for comment API routing
          }))
        : [];
      return {
        ...state,
        jobReadyData: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
        // Store checklist items with screenKey (with canUpdate injected)
        checklists: {
          ...state.checklists,
          [screenKey]: {
            isLoading: false,
            error: null,
            data: checklistDataWithCanUpdate,
          },
        },
      };
    }

    case GET_JOB_READY_DATA_FAILED:
      return {
        ...state,
        jobReadyData: {
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_JOB_READY_DATA_PROGRESS:
      return {
        ...state,
        jobReadyData: {
          ...state.jobReadyData,
          isLoading: action.payload,
        },
      };

    case SUBMIT_JOB_READY_FORM_SUCCESS:
      return {
        ...state,
        submitJobReady: {
          isLoading: false,
          error: null,
          data: true,
        },
      };

    case SUBMIT_JOB_READY_FORM_FAILED:
      return {
        ...state,
        submitJobReady: {
          isLoading: false,
          error: action.payload,
          data: false,
        },
      };

    case SUBMIT_JOB_READY_FORM_PROGRESS:
      return {
        ...state,
        submitJobReady: {
          ...state.submitJobReady,
          isLoading: action.payload,
        },
      };

    case SAVE_JOB_READY_ITEM_SUCCESS: {
      // screenKey comes from action payload
      const screenKey = (action as any).screenKey;
      if (!screenKey) return state; // No key = no update
      const jobReadyChecklist = state.checklists[screenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        saveJobReadyItem: {
          isLoading: false,
          error: null,
          data: true,
        },
        // Update the checklist item in checklists state
        checklists: {
          ...state.checklists,
          [screenKey]: {
            ...jobReadyChecklist,
            data: Array.isArray(jobReadyChecklist.data)
              ? jobReadyChecklist.data.map(item =>
                  item.id === action.payload?.id
                    ? { ...item, ...action.payload }
                    : item,
                )
              : [],
          },
        },
      };
    }

    case SAVE_JOB_READY_ITEM_FAILED:
      return {
        ...state,
        saveJobReadyItem: {
          isLoading: false,
          error: action.payload,
          data: false,
        },
      };

    case SAVE_JOB_READY_ITEM_PROGRESS:
      return {
        ...state,
        saveJobReadyItem: {
          ...state.saveJobReadyItem,
          isLoading: action.payload,
        },
      };

    case UPDATE_JOB_READY_ITEM_OPTION: {
      // screenKey comes from payload (passed from Content)
      const screenKey = action.payload.screenKey;
      if (!screenKey) return state; // No key = no update
      const currentChecklist = state.checklists[screenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [screenKey]: {
            ...currentChecklist,
            data: Array.isArray(currentChecklist.data)
              ? currentChecklist.data.map(item =>
                  item.id === action.payload.itemId
                    ? { ...item, selectedOption: action.payload.selectedOption }
                    : item,
                )
              : [],
          },
        },
      };
    }

    case CLEAR_JOB_READY_DATA: {
      // Clear checklist by screenKey from payload
      const screenKeyToClear = (action as any).screenKey;
      if (!screenKeyToClear) return state; // No key = no clear
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { [screenKeyToClear]: _removed, ...remainingChecklists } =
        state.checklists;
      return {
        ...state,
        jobReadyData: {
          data: null,
          isLoading: false,
          error: null,
        },
        checklists: remainingChecklists,
        submitJobReady: {
          data: false,
          isLoading: false,
          error: null,
        },
        saveJobReadyItem: {
          data: false,
          isLoading: false,
          error: null,
        },
      };
    }

    // ========================================================================
    // Job Start Checklist Cases
    // ========================================================================

    case GET_JOB_START_DATA_SUCCESS: {
      const data = action.payload;
      // Map jobStartChecklist items to include jobStartChecklistId for mode detection
      const mappedChecklist = (data.jobStartChecklist || []).map(
        (item: any) => ({
          ...item,
          // Add jobStartChecklistId for mode detection in ChecklistItemContent
          // This field is used by detectChecklistMode() to identify JOB_START mode
          jobStartChecklistId: item.id,
          // Add screenKey for API routing in comment modal
          screenKey: 'jobStart',
        }),
      );

      return {
        ...state,
        jobStartData: {
          isLoading: false,
          error: null,
          data: {
            ...data,
            jobStartChecklist: mappedChecklist,
          },
        },
        // Also store in checklists for Checklist component
        // Key must match SCREEN_ENUM.JobStartChecklistScreen
        checklists: {
          ...state.checklists,
          [SCREEN_KEY_JOB_START]: {
            isLoading: false,
            error: null,
            data: mappedChecklist,
          },
        },
      };
    }

    case GET_JOB_START_DATA_FAILED:
      return {
        ...state,
        jobStartData: {
          isLoading: false,
          error: action.payload,
          data: null,
        },
      };

    case GET_JOB_START_DATA_PROGRESS:
      return {
        ...state,
        jobStartData: {
          ...state.jobStartData,
          isLoading: action.payload,
        },
      };

    case UPDATE_MATERIAL_RECEIVED: {
      // Update material checklist item's quantitySave and calculate quantityMissing
      const { id, quantity } = action.payload;
      if (!state.jobStartData.data) return state;

      const updatedMaterials = state.jobStartData.data.materialChecklists.map(
        item => {
          if (item.id === id) {
            const missing = item.verifyMaterial - quantity;
            return {
              ...item,
              quantitySave: quantity,
              quantityMissing: missing > 0 ? missing : null,
            };
          }
          return item;
        },
      );

      return {
        ...state,
        jobStartData: {
          ...state.jobStartData,
          data: {
            ...state.jobStartData.data,
            materialChecklists: updatedMaterials,
          },
        },
      };
    }

    case UPDATE_JOB_START_CHECKLIST_TOGGLE: {
      // Update jobStartChecklist item's isChecked
      // Only update isChecked field, preserve all other data (comment, files, responses)
      const { id, isChecked } = action.payload;
      if (!state.jobStartData.data) return state;

      // Update in jobStartData source
      const updatedJobStartChecklists =
        state.jobStartData.data.jobStartChecklist.map(item => {
          if (item.id === id) {
            return {
              ...item,
              isChecked,
            };
          }
          return item;
        });

      // Update in checklists independently to preserve response data (comment, files)
      const currentChecklistData =
        state.checklists?.[SCREEN_KEY_JOB_START]?.data;
      const updatedChecklistData = Array.isArray(currentChecklistData)
        ? currentChecklistData.map((item: any) => {
            if (item.id === id) {
              return {
                ...item,
                isChecked,
              };
            }
            return item;
          })
        : updatedJobStartChecklists;

      return {
        ...state,
        jobStartData: {
          ...state.jobStartData,
          data: {
            ...state.jobStartData.data,
            jobStartChecklist: updatedJobStartChecklists,
          },
        },
        // Sync to checklists but preserve existing data (responses, comments, files)
        checklists: {
          ...state.checklists,
          [SCREEN_KEY_JOB_START]: {
            ...state.checklists?.[SCREEN_KEY_JOB_START],
            data: updatedChecklistData as any,
          },
        },
      };
    }

    case SUBMIT_JOB_START_SUCCESS:
      return {
        ...state,
        submitJobStart: {
          isLoading: false,
          error: null,
          data: true,
        },
      };

    case SUBMIT_JOB_START_FAILED:
      return {
        ...state,
        submitJobStart: {
          isLoading: false,
          error: action.payload,
          data: false,
        },
      };

    case SUBMIT_JOB_START_PROGRESS:
      return {
        ...state,
        submitJobStart: {
          ...state.submitJobStart,
          isLoading: action.payload,
        },
      };

    case CLEAR_JOB_START_DATA:
      return {
        ...state,
        jobStartData: {
          data: null,
          isLoading: false,
          error: null,
        },
        submitJobStart: {
          data: false,
          isLoading: false,
          error: null,
        },
      };

    // Work Order Participants
    case GET_WORK_ORDER_PARTICIPANTS_SUCCESS:
      return {
        ...state,
        participants: {
          data: action.payload,
          isLoading: false,
          error: null,
        },
      };

    case GET_WORK_ORDER_PARTICIPANTS_FAILED:
      return {
        ...state,
        participants: {
          ...state.participants,
          isLoading: false,
          error: action.payload,
        },
      };

    case GET_WORK_ORDER_PARTICIPANTS_PROGRESS:
      return {
        ...state,
        participants: {
          ...state.participants,
          isLoading: action.payload,
        },
      };

    case CLEAR_WORK_ORDER_PARTICIPANTS:
      return {
        ...state,
        participants: {
          data: [],
          isLoading: false,
          error: null,
        },
      };

    // Work Order Detail Participants
    case GET_WORK_ORDER_DETAIL_PARTICIPANTS_SUCCESS:
      return {
        ...state,
        participantWorkOrder: {
          data: action.payload,
          isLoading: false,
          error: null,
        },
      };

    case GET_WORK_ORDER_DETAIL_PARTICIPANTS_FAILED:
      return {
        ...state,
        participantWorkOrder: {
          ...state.participantWorkOrder,
          isLoading: false,
          error: action.payload,
        },
      };

    case GET_WORK_ORDER_DETAIL_PARTICIPANTS_PROGRESS:
      return {
        ...state,
        participantWorkOrder: {
          ...state.participantWorkOrder,
          isLoading: action.payload,
        },
      };

    case CLEAR_WORK_ORDER_DETAIL_PARTICIPANTS:
      return {
        ...state,
        participantWorkOrder: {
          data: null,
          isLoading: false,
          error: null,
        },
      };

    // ========================================================================
    // Material Delivered (read-only work order + delivery chat)
    // ========================================================================

    case GET_MATERIAL_DELIVERED_SUCCESS:
      return {
        ...state,
        materialDelivered: {
          data: action.payload,
          isLoading: false,
          error: null,
        },
      };

    case GET_MATERIAL_DELIVERED_FAILED:
      return {
        ...state,
        materialDelivered: {
          ...state.materialDelivered,
          isLoading: false,
          error: action.payload,
        },
      };

    case GET_MATERIAL_DELIVERED_PROGRESS:
      return {
        ...state,
        materialDelivered: {
          ...state.materialDelivered,
          isLoading: action.payload,
        },
      };

    case GET_MATERIAL_DELIVERED_CHAT_SUCCESS:
      return {
        ...state,
        materialDeliveredChat: {
          data: action.payload,
          isLoading: false,
          error: null,
        },
      };

    case GET_MATERIAL_DELIVERED_CHAT_FAILED:
      return {
        ...state,
        materialDeliveredChat: {
          ...state.materialDeliveredChat,
          isLoading: false,
          error: action.payload,
        },
      };

    case GET_MATERIAL_DELIVERED_CHAT_PROGRESS:
      return {
        ...state,
        materialDeliveredChat: {
          ...state.materialDeliveredChat,
          isLoading: action.payload,
        },
      };

    case CLEAR_MATERIAL_DELIVERED:
      return {
        ...state,
        materialDelivered: {
          data: null,
          isLoading: false,
          error: null,
        },
        materialDeliveredChat: {
          data: null,
          isLoading: false,
          error: null,
        },
      };

    // ============================================================================
    // QI Inspection
    // ============================================================================

    case TOGGLE_QI_INSPECTION_CHECK: {
      // LOCAL ONLY toggle — no API call. Flips isChecked for item in QIInspectionScreen keyed state.
      const qiScreenKey = SCREEN_KEY_QI_INSPECTION;
      const qiChecklist = state.checklists[qiScreenKey] || {
        data: [],
        isLoading: false,
        error: null,
      };
      return {
        ...state,
        checklists: {
          ...state.checklists,
          [qiScreenKey]: {
            ...qiChecklist,
            data: Array.isArray(qiChecklist.data)
              ? qiChecklist.data.map(item =>
                  item.id === action.payload.itemId
                    ? {
                        ...item,
                        isChecked: !item.isChecked,
                      }
                    : item,
                )
              : [],
          },
        },
      };
    }

    case CLEAR_QI_INSPECTION: {
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { QIInspectionScreen: _removed, ...remainingChecklists } =
        state.checklists;
      return {
        ...state,
        checklists: remainingChecklists,
      };
    }

    default:
      return state;
  }
}

