export const fetchSaveWorkOrderChecklist = async (
  payload: SaveWorkOrderChecklistPayload,
) => {
  try {
    const formData = new FormData();
    formData.append('id', payload.id);
    formData.append('isCompleted', String(payload.isCompleted));

    if (payload.comments !== undefined) {
      formData.append('comments', payload.comments);
    }
    if (payload.reason !== undefined) {
      formData.append('reason', payload.reason);
    }
    if (payload.checkListJson && payload.checkListJson.length > 0) {
      formData.append('checkListJson', JSON.stringify(payload.checkListJson));
    }

    const response = await client.post(saveWorkOrderChecklist, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
    return {
      status: response.status,
      code: response.status,
      data: response.data?.data,
    };
  } catch (error: any) {
    logger('error fetchSaveWorkOrderChecklist', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

