// Comment for JobReady checklist (uses saveCommentProjectReady endpoint with FormData)
// When notS3 is true, files are appended directly to FormData instead of S3 URLs
export const fetchCommentProjectReady = async (payload: CommentPayload) => {
  try {
    const formData = new FormData();
    formData.append('id', payload.id);
    
    if (payload.comment !== undefined) {
      formData.append('comment', payload.comment);
    }
    if (payload.isChecked !== undefined) {
      formData.append('isChecked', String(payload.isChecked));
    }
    if (payload.isNA !== undefined) {
      formData.append('isNA', String(payload.isNA));
    }
    if (payload.reason !== undefined) {
      formData.append('reason', payload.reason);
    }
    if (payload.selectedOption !== undefined) {
      formData.append('selectedOption', String(payload.selectedOption));
    }

    // Handle files - notS3 mode appends files directly
    if (payload.fileDatas && payload.fileDatas.length > 0) {
      if (payload.notS3) {
        // notS3 mode: Append files directly to FormData with key 'FileEntities'
        for (const file of payload.fileDatas) {
          const fileUri = file.uri || file.path;
          if (fileUri) {
            const isVideo = file.mime?.includes('video');
            formData.append('FileEntities', {
              uri: fileUri,
              type: file.mime || 'image/jpeg',
              name: file.fileName || (isVideo ? 'video.mp4' : 'photo.jpg'),
            } as any);
          }
        }
      } else {
        // Normal mode: Send file data as JSON (S3 URLs)
        formData.append('fileDatas', JSON.stringify(payload.fileDatas));
      }
    }

    const response = await client.put(saveCommentProjectReady, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
    return {
      status: response.status,
      code: response.status,
      data: response.data?.data,
    };
  } catch (error: any) {
    logger('error fetchCommentProjectReady', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

