/**
 * Save job start checklist comment/files (S3 upload pattern - JSON with fileDatas URLs)
 * PUT /api/wo-checklist/save-job-start-checklist-response
 */
export const fetchCommentJobStart = async (payload: CommentPayload) => {
  try {
    const body: {
      id: string;
      comment?: string;
      fileDatas?: any[];
    } = {
      id: payload.id,
    };

    if (payload.comment !== undefined) {
      body.comment = payload.comment;
    }

    // fileDatas should already be in S3 format: { fileId, fileName, fileLength, fileExtension, key, url }
    if (payload.fileDatas && payload.fileDatas.length > 0) {
      body.fileDatas = payload.fileDatas;
    }

    const response = await client.put(
      saveJobStartChecklistCommentEndpoint,
      body,
    );
    return {
      status: response.status,
      code: response.status,
      data: response.data?.data,
    };
  } catch (error: any) {
    logger('error fetchCommentJobStart', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

