// Helper functions
const getDefaultFileInfo = (mime: string) => {
  const isVideo = mime?.startsWith('video/');
  const extension = isVideo ? 'mp4' : 'jpg';
  return {
    name: `file_${Date.now()}.${extension}`,
    extension: `.${extension}`,
  };
};

const isVideoFile = (mime: string) => mime?.startsWith('video/');

const getWorkOrderDetail = function* (action: {
  type: string;
  payload: GetWorkOrderDetailPayload;
}): Generator<any, void, any> {
  try {
    yield put({ type: GET_WORK_ORDER_DETAIL_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(
      fetchJobDetail,
      action.payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_WORK_ORDER_DETAIL_FAILED,
        payload: response.message,
      });
      return;
    }

    yield put({
      type: GET_WORK_ORDER_DETAIL_SUCCESS,
      payload: response.data,
    });

    // Map checklists với canUpdate, reason, và screenKey từ parent canUpdateChecklist
    const screenKey = action.payload.screenKey;
    let mappedChecklists = response.data.checklists?.map(
      (checklist: ChecklistItem) => ({
        ...checklist,
        canUpdate: response.data.canUpdateChecklist?.canUpdate,
        reason: response.data.canUpdateChecklist?.reason,
        userRole: response.data.companyRoleInfo?.roleType,
        screenKey: screenKey, // Inject screenKey for comment API routing
      }),
    );

    // QI WaitingReinspect: hide items already Yes (isChecked === true)
    // Show: No (false), NA, null (not yet chosen) — user needs to update these
    // After local toggle (Yes), item stays visible — re-filter only on re-fetch
    const jobQIStatus = response.data?.qIStatus;
    if (jobQIStatus === QIStatusEnum.WaitingReinspect) {
      mappedChecklists = mappedChecklists?.filter(
        (item: ChecklistItem) => item.isChecked !== true,
      );
    }

    yield put({
      type: GET_CHECKLIST_SUCCESS,
      payload: mappedChecklists,
      screenKey: screenKey,
    });
  } catch (error) {
    yield put({ type: GET_WORK_ORDER_DETAIL_FAILED, payload: error });
  } finally {
    yield put({ type: GET_WORK_ORDER_DETAIL_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

