const saveJobReadyItem = function* (action: {
  type: string;
  payload: SaveJobReadyItemPayload;
}): Generator<any, void, any> {
  const { onSuccess, onError, ...payload } = action.payload;

  try {
    yield put({ type: SAVE_JOB_READY_ITEM_PROGRESS, payload: true });

    const response = (yield call(
      fetchSaveJobReadyItem,
      payload,
    )) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: SAVE_JOB_READY_ITEM_FAILED,
        payload: response.message,
      });

      if (onError) {
        onError(response.message);
      }
      return;
    }

    // Merge response with payload's selectedOption to ensure local state is correct
    // BE may not return selectedOption or return old value
    const mergedData = {
      ...response.data,
      id: payload.itemId, // Ensure id matches for reducer lookup
      selectedOption: payload.selectedOption, // Override with submitted value
    };

    yield put({
      type: SAVE_JOB_READY_ITEM_SUCCESS,
      payload: mergedData,
      screenKey: action.payload.screenKey,
    });

    if (onSuccess) {
      onSuccess();
    }
  } catch (error: any) {
    logger('Error in saveJobReadyItem:', error);
    yield put({ type: SAVE_JOB_READY_ITEM_FAILED, payload: error });

    if (onError) {
      onError(error);
    }
  } finally {
    yield put({ type: SAVE_JOB_READY_ITEM_PROGRESS, payload: false });
  }
};

