const submitJobStart = function* (action: {
  type: string;
  payload: SubmitJobStartPayload;
}): Generator<any, void, any> {
  const { onSuccess, onError, ...payload } = action.payload;

  try {
    yield put({ type: SUBMIT_JOB_START_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    const response = (yield call(fetchSubmitJobStart, payload)) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: SUBMIT_JOB_START_FAILED,
        payload: response.message,
      });

      if (onError) {
        onError(response.message);
      }

      Toast.show({
        type: 'error',
        text1: i18n.t('common:ERROR'),
        text2: response.message || i18n.t('common:SOMETHING_WENT_WRONG'),
      });
      return;
    }

    yield put({
      type: SUBMIT_JOB_START_SUCCESS,
      payload: response.data,
    });

    if (onSuccess) {
      onSuccess();
    }
  } catch (error: any) {
    logger('Error in submitJobStart:', error);
    yield put({ type: SUBMIT_JOB_START_FAILED, payload: error });

    if (onError) {
      onError(error);
    }
  } finally {
    yield put({ type: HIDE_LOADING_OVERLAY });
    yield put({ type: SUBMIT_JOB_START_PROGRESS, payload: false });
  }
};

/**
 * Save Job Start Checklist isChecked (auto-save)
 * Optimistic update: Redux updated first, then API called in background
 */
const saveJobStartChecklistIsCheckedSaga = function* (action: any): Generator {
  const { id, isChecked } = action.payload;

  // Step 1: Update Redux immediately (optimistic update done by reducer)
  yield put({ type: UPDATE_JOB_START_CHECKLIST_TOGGLE, payload: { id, isChecked } });

  // Step 2: Call API in background (no loading overlay for smooth UX)
  try {
    const response = (yield call(saveJobStartChecklistIsChecked, {
      id,
      isChecked,
    })) as ResponseApi;

    if (response.status !== 200) {
      // Silently log error - could add retry logic or revert if needed
      console.log('saveJobStartChecklistIsChecked failed:', response.message);
    }
  } catch (error) {
    console.log('saveJobStartChecklistIsChecked error:', error);
  }
};

