/**
 * Fetch QI Inspection data — Leader reviews Inspector's incomplete items.
 * Same API as original QuantityInspectionChecklist screen.
 * Filters: only show !isChecked && !isNA items.
 * Transforms: adds qiStatus, needCommentNow, hideCheckBox, screenKey.
 */
const getQIInspection = function* (action: {
  type: string;
  payload: { scheduleId: string };
}): Generator<any, void, any> {
  const QI_SCREEN_KEY = SCREEN_KEY_QI_INSPECTION;
  try {
    yield put({ type: GET_QI_INSPECTION_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    const response = (yield call(
      fetchQIInspectionData,
      action.payload.scheduleId,
    )) as ResponseApi;

    if (response.status !== 200) {
      yield put({ type: GET_QI_INSPECTION_FAILED, payload: response.message });
      return;
    }

    const resData = response.data;
    const currentQIStatus: QIStatusEnum = resData?.qIStatus;

    logger('[QI Inspection] qIStatus:', currentQIStatus, '| canRequestReInspect:', resData?.canRequestReInspect, '| totalIncomplete:', resData?.totalIncomplete, '| checklists count:', resData?.checklists?.length);

    // Only show failed items (isChecked === false). Hide Yes and NA.
    const allChecklists = (resData?.checklists || []).filter(
      (a: any) => a.isChecked === false,
    );

    // Determine visibility flags (matches original code line 113-128)
    const hideCheckBox =
      currentQIStatus === QIStatusEnum.Pending ||
      currentQIStatus === QIStatusEnum.WaitingReinspect;
    const hideComment =
      currentQIStatus === QIStatusEnum.Pending ||
      currentQIStatus === QIStatusEnum.WaitingReinspect ||
      currentQIStatus === QIStatusEnum.Completed;
    const leaderCheckIncomplete =
      currentQIStatus === QIStatusEnum.WaitingForFixes &&
      (resData?.totalIncomplete ?? 0) > 0;

    // Transform items with QI-specific metadata
    const transformedItems = allChecklists.map((item: any) => {
      const lastResponse = item.response?.[item.response.length - 1];
      const needCommentNow =
        (currentQIStatus === QIStatusEnum.WaitingForFixes ||
          currentQIStatus === QIStatusEnum.WaitingReinspect) &&
        lastResponse?.isExMyResponse === false;

      return {
        ...item,
        qiStatus: currentQIStatus,
        hideCheckBox,
        hideComment,
        leaderCheckIncomplete,
        needCommentNow,
        canRequestReInspect: resData?.canRequestReInspect ?? false,
        screenKey: QI_SCREEN_KEY,
      };
    });

    // Store in keyed checklist state
    yield put({
      type: GET_CHECKLIST_SUCCESS,
      payload: transformedItems,
      screenKey: QI_SCREEN_KEY,
    });

    yield put({
      type: GET_QI_INSPECTION_SUCCESS,
      payload: {
        ...resData,
        checklists: transformedItems,
      },
    });
  } catch (error) {
    yield put({ type: GET_QI_INSPECTION_FAILED, payload: error });
  } finally {
    yield put({ type: GET_QI_INSPECTION_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

/**
 * Request Reinspect — Leader asks Inspector to re-check items.
 * Calls POST /api/quantity-inspection/request-resubmit
 * On success: Toast + goBack()
 */
const requestReinspect = function* (action: {
  type: string;
  payload: {
    scheduleActivityId: string;
    onSuccess?: () => void;
    onError?: (error: any) => void;
  };
}): Generator<any, void, any> {
  const { onSuccess, onError } = action.payload;
  try {
    yield put({ type: SHOW_LOADING_OVERLAY });

    const response = (yield call(
      fetchRequestReinspect,
      action.payload.scheduleActivityId,
    )) as ResponseApi;

    if (response.status !== 200) {
      yield put({ type: REQUEST_REINSPECT_FAILED, payload: response.message });

      yield call(Toast.show, {
        text1: response.message || i18n.t('REQUEST_REINSPECT_FAILED'),
        type: 'error',
      });
      if (onError) onError(response.message);
      return;
    }

    yield put({ type: REQUEST_REINSPECT_SUCCESS, payload: response.data });
    yield put({ type: CLEAR_QI_INSPECTION });

    yield call(Toast.show, {
      text1: i18n.t('REQUEST_REINSPECT_SENT_SUCCESSFULLY'),
      type: 'success',
    });

    // Callback to Content hook — handles navigation (goBack)
    if (onSuccess) onSuccess();
  } catch (error) {
    yield put({ type: REQUEST_REINSPECT_FAILED, payload: error });
    yield call(Toast.show, {
      text1: i18n.t('REQUEST_REINSPECT_FAILED'),
      type: 'error',
    });
    if (onError) onError(error);
  } finally {
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};


